listitem.programlisting:
it.redisLettuce()
  .pollSscan {
    connection {
      nodes = redis://localhost:6439
      database = 0
      redisConnectionType = RedisConnectionType.SINGLE
      authPassword = "    authPassword = "Brother1999"
      authUser = "JohnJacobson"
    }
    keyOrPattern(sscan)
    pollDelay(Duration.ofSeconds(1))
}

.redisLettuce()
.save {
  connection {
    nodes = redis://localhost:6439
    database = 0
    redisConnectionType = RedisConnectionType.SINGLE
    authPassword = "Brother1999"
    authUser = "JohnJacobson"
    }

  records { _, input ->
    listOf(
      SetRecord("battery_state_save_and_poll",
        objectMapper.writeValueAsString(input)
      )
    )
   }
}

redisLettuce()
  .streamsConsume {
        connection {
            nodes = redis://localhost:6439
            database = 0
            redisConnectionType = RedisConnectionType.SINGLE
            authPassword = "Brother1999"
            authUser = "JohnJacobson"
        }
        streamKey("battery_state_produce_and_consume")
        offset("FROM_BEGINNING")
        group("consumer")
  }

.redisLettuce()
.streamsProduce {
  connection {
    nodes = redis://localhost:6439
    database = 0
    redisConnectionType = RedisConnectionType.SINGLE
    authPassword = "Brother1999"
    authUser = "JohnJacobson"
  }

  records { _, input ->
    listOf(
     LettuceStreamsProduceRecord(
        key = "battery_state_produce_and_consume", value = mapOf(
            "device_id" to input.deviceId,
            "timestamp" to input.timestamp.epochSecond.toString(),
            "battery_level" to input.batteryLevel.toString()
          )
      )
   )
  }
}
